$tours[] = [
  'title' => 'Eternal Rome: From the Colosseum to the Trevi Fountain',
  'description' => 'Walk through three thousand years of history on this unforgettable tour of Rome\'s most celebrated landmarks. The Eternal City is unlike anywhere else on earth — a place where an ancient Roman temple stands next to a Renaissance church, where Baroque fountains erupt from medieval piazzas, and where the weight of history is felt on every street corner. This tour takes you from the mighty Colosseum and the Roman Forum — the political and civic heart of the ancient world — through the winding streets of the historic centre to the Vatican Museums, the Sistine Chapel, and the incomparable Trevi Fountain. Whether it\'s your first visit to Rome or your tenth, this city never fails to overwhelm and inspire.',
  'duration' => 240,
  'country' => 'Italy',
  'city' => 'Rome',
  'location' => ['lat' => 41.9028, 'lng' => 12.4964],
  'translations' => [
    'es' => [
      'title' => 'Roma eterna: del Coliseo a la Fontana di Trevi',
      'description' => 'Recorra tres mil años de historia en este inolvidable tour por los monumentos más célebres de Roma. La Ciudad Eterna es un lugar donde un templo romano antiguo se alza junto a una iglesia renacentista, donde fuentes barrocas brotan de plazas medievales y el peso de la historia se siente en cada esquina. Este recorrido le lleva del majestuoso Coliseo y el Foro Romano hasta los Museos Vaticanos, la Capilla Sixtina y la incomparable Fontana di Trevi.',
    ],
    'fr' => [
      'title' => 'Rome éternelle : du Colisée à la Fontaine de Trevi',
      'description' => 'Traversez trois mille ans d\'histoire lors de cette visite inoubliable des monuments les plus célèbres de Rome. La Ville Éternelle est un lieu où un temple romain antique côtoie une église Renaissance, où des fontaines baroques jaillissent de piazzas médiévales et où le poids de l\'histoire se ressent à chaque coin de rue. Ce parcours vous mène du majestueux Colisée et du Forum Romain aux Musées du Vatican, à la Chapelle Sixtine et à l\'incomparable Fontaine de Trevi.',
    ],
    'de' => [
      'title' => 'Ewiges Rom: Vom Kolosseum zum Trevi-Brunnen',
      'description' => 'Wandern Sie durch dreitausend Jahre Geschichte auf dieser unvergesslichen Tour durch Roms berühmteste Wahrzeichen. Die Ewige Stadt ist ein Ort, wo ein antiker römischer Tempel neben einer Renaissance-Kirche steht, wo Barockbrunnen aus mittelalterlichen Piazzas emporspringen und wo das Gewicht der Geschichte an jeder Straßenecke spürbar ist. Diese Tour führt vom mächtigen Kolosseum und dem Forum Romanum zu den Vatikanischen Museen, der Sixtinischen Kapelle und dem unvergleichlichen Trevi-Brunnen.',
    ],
    'it' => [
      'title' => 'Roma eterna: dal Colosseo alla Fontana di Trevi',
      'description' => 'Attraversate tremila anni di storia in questo tour indimenticabile dei monumenti più celebri di Roma. La Città Eterna è un luogo dove un tempio romano antico sorge accanto a una chiesa rinascimentale, dove fontane barocche erompono da piazze medievali e il peso della storia si avverte ad ogni angolo. Questo percorso vi porta dal maestoso Colosseo e dal Foro Romano ai Musei Vaticani, alla Cappella Sistina e all\'incomparabile Fontana di Trevi.',
    ],
    'el' => [
      'title' => 'Αιώνια Ρώμη: από το Κολοσσαίο στη Φοντάνα ντι Τρέβι',
      'description' => 'Περπατήστε μέσα από τρεις χιλιάδες χρόνια ιστορίας σε αυτήν την αξέχαστη περιήγηση στα πιο διάσημα αξιοθέατα της Ρώμης. Η Αιώνια Πόλη είναι σε αντίθεση με οτιδήποτε άλλο στη γη — ένα μέρος όπου ένας αρχαίος ρωμαϊκός ναός στέκεται δίπλα σε μια αναγεννησιακή εκκλησία, όπου μπαρόκ συντριβάνια εκρήγνυνται από μεσαιωνικές πλατείες. Αυτή η περιήγηση σας φέρνει από το Κολοσσαίο και το Ρωμαϊκό Φόρουμ μέχρι τα Μουσεία του Βατικανού, την Καπέλα Σιστίνα και την ασύγκριτη Φοντάνα ντι Τρέβι.',
    ],
  ],
  'steps' => [
    [
      'title' => 'The Colosseum — Rome\'s Greatest Arena',
      'order' => 1,
      'location' => ['lat' => 41.8902, 'lng' => 12.4922],
      'description' => 'Begin your Roman journey at the Colosseum — the Flavian Amphitheatre — the largest ancient amphitheatre ever built and an enduring symbol of Imperial Rome\'s power, ambition, and brutality. Commissioned by Emperor Vespasian around 70 AD and completed under his son Titus in 80 AD, the Colosseum could hold between 50,000 and 80,000 spectators who came to watch gladiatorial combat, wild animal hunts (venationes), public executions, and dramatic re-enactments of famous battles. The engineering achievement is extraordinary even by modern standards: the elliptical structure is 188 metres long, 156 metres wide, and 48 metres tall, constructed using approximately 100,000 cubic metres of travertine marble — all transported from quarries near Tivoli — along with volcanic tuff, brick, and concrete. The complex system of underground tunnels and chambers (the hypogeum), only recently opened to visitors, housed the animals, gladiators, and mechanical elevators used to raise participants dramatically into the arena. The Colosseum was in continuous use for nearly 400 years before being converted into housing, workshops, a religious complex, and ultimately a quarry during the medieval period — which explains the missing sections of the outer wall. Today it remains one of the most visited monuments in the world, attracting over 7 million visitors annually. Book skip-the-line tickets online — the queues without pre-booking are formidable.',
      'translations' => [
        'es' => ['title' => 'El Coliseo — la mayor arena de Roma', 'description' => 'Comience su recorrido romano en el Coliseo — el Anfiteatro Flavio — el mayor anfiteatro antiguo jamás construido y símbolo perdurable del poder de la Roma Imperial. Encargado por el emperador Vespasiano alrededor del año 70 d.C. y completado bajo su hijo Tito en el 80 d.C., podía albergar entre 50.000 y 80.000 espectadores. La estructura elíptica mide 188 metros de largo, 156 de ancho y 48 de alto, construida con aproximadamente 100.000 metros cúbicos de mármol travertino. El complejo sistema de túneles subterráneos (el hipogeo), recientemente abierto al público, alojaba animales, gladiadores y elevadores mecánicos. Reserve entradas sin cola online.'],
        'fr' => ['title' => 'Le Colisée — la plus grande arène de Rome', 'description' => 'Commencez votre voyage romain au Colisée — l\'Amphithéâtre Flavien — le plus grand amphithéâtre antique jamais construit. Commandé par l\'empereur Vespasien vers 70 apr. J.-C. et achevé sous son fils Titus en 80 apr. J.-C., il pouvait accueillir entre 50 000 et 80 000 spectateurs. La structure elliptique mesure 188 mètres de long, 156 de large et 48 de haut, construite avec environ 100 000 mètres cubes de marbre travertin. Le système complexe de tunnels souterrains (l\'hypogée), récemment ouvert aux visiteurs, abritait animaux, gladiateurs et ascenseurs mécaniques. Réservez des billets coupe-file en ligne.'],
        'de' => ['title' => 'Das Kolosseum — Roms größte Arena', 'description' => 'Beginnen Sie Ihre römische Reise am Kolosseum — dem Flavischen Amphitheater — dem größten antiken Amphitheater, das je gebaut wurde. Um 70 n. Chr. von Kaiser Vespasian in Auftrag gegeben und unter seinem Sohn Titus 80 n. Chr. vollendet, fasste es zwischen 50.000 und 80.000 Zuschauer. Die elliptische Struktur ist 188 Meter lang, 156 Meter breit und 48 Meter hoch, aus rund 100.000 Kubikmetern Travertin erbaut. Das komplexe System unterirdischer Tunnel (das Hypogäum), erst kürzlich für Besucher geöffnet, beherbergte Tiere, Gladiatoren und mechanische Aufzüge. Buchen Sie Tickets ohne Warteschlange online.'],
        'it' => ['title' => 'Il Colosseo — la più grande arena di Roma', 'description' => 'Iniziate il vostro viaggio romano al Colosseo — l\'Anfiteatro Flavio — il più grande anfiteatro antico mai costruito. Commissionato dall\'imperatore Vespasiano intorno al 70 d.C. e completato sotto suo figlio Tito nell\'80 d.C., poteva ospitare tra 50.000 e 80.000 spettatori. La struttura ellittica misura 188 metri di lunghezza, 156 di larghezza e 48 di altezza, costruita con circa 100.000 metri cubi di travertino. Il complesso sistema di tunnel sotterranei (l\'ipogeo), recentemente aperto ai visitatori, ospitava animali, gladiatori e ascensori meccanici. Prenotate biglietti salta-fila online.'],
        'el' => ['title' => 'Το Κολοσσαίο — η μεγαλύτερη αρένα της Ρώμης', 'description' => 'Ξεκινήστε το ρωμαϊκό ταξίδι σας στο Κολοσσαίο — το Φλαβιανό Αμφιθέατρο — το μεγαλύτερο αρχαίο αμφιθέατρο που χτίστηκε ποτέ και ένα αντίκτυπο σύμβολο της δύναμης, φιλοδοξίας και βαρβαρότητας της Αυτοκρατορικής Ρώμης. Παραγγελθέν από τον Αυτοκράτορα Βεσπασιανό γύρω στο 70 μ.Χ. και ολοκληρωμένο υπό τον γιο του Τίτο το 80 μ.Χ., μπορούσε να χωρέσει μεταξύ 50.000 και 80.000 θεατές. Η ελλειπτική δομή έχει μήκος 188 μέτρα, πλάτος 156 μέτρα και ύψος 48 μέτρα, κατασκευασμένη από περίπου 100.000 κυβικά μέτρα τραβερτίνη. Το σύστημα υπόγειων τούνελ (το υπόγειο), πρόσφατα ανοιχτό στο κοινό, στέγαζε ζώα, μονομάχους και μηχανικά ανελκυστήρα. Κλείστε εισιτήρια που παρακάμπτουν την ουρά ηλεκτρονικά.'],
      ],
    ],
    [
      'title' => 'Roman Forum & Palatine Hill',
      'order' => 2,
      'location' => ['lat' => 41.8925, 'lng' => 12.4853],
      'description' => 'Immediately adjacent to the Colosseum lies the Roman Forum — the Foro Romano — the beating heart of the ancient Roman world for over a thousand years. This sprawling archaeological site, now a romantic landscape of towering columns, triumphal arches, ruined temples, and basilicas, was once the centre of Roman public life: the place where elections were held, criminals tried, gladiators honoured, and emperors mourned. Walking through the Forum today requires some imagination to reconstruct its former glory, but the individual monuments are remarkable. The Temple of Saturn (497 BC), one of the oldest temples in Rome, still stands with eight of its grey granite columns intact. The Arch of Titus (81 AD), erected to commemorate the sack of Jerusalem, features interior reliefs showing Roman soldiers carrying the Menorah from the Temple — these images had a profound influence on later triumphal arch design throughout Europe. The Temple of Vesta, where the sacred flame of Rome was kept burning by the Vestal Virgins, is one of the most evocative ruins in the entire complex. From the Forum, climb the Palatine Hill — the most central of Rome\'s seven hills and, according to legend, the location of the city\'s founding by Romulus in 753 BC — for spectacular panoramic views over the Forum below and the Circus Maximus, ancient Rome\'s chariot-racing stadium, on the other side.',
      'translations' => [
        'es' => ['title' => 'Foro Romano y Monte Palatino', 'description' => 'Junto al Coliseo se extiende el Foro Romano, corazón palpitante del mundo romano antiguo durante más de mil años. El Templo de Saturno (497 a.C.) conserva ocho de sus columnas de granito gris. El Arco de Tito (81 d.C.), erigido para conmemorar el saqueo de Jerusalén, presenta relieves interiores con soldados romanos portando la Menorá del Templo. El Templo de Vesta, donde las Vestales mantenían encendida la llama sagrada de Roma, es una de las ruinas más evocadoras. Desde el Foro, suba al Monte Palatino — según la leyenda, el lugar de la fundación de Roma por Rómulo en 753 a.C. — para vistas panorámicas del Foro y el Circo Máximo.'],
        'fr' => ['title' => 'Le Forum Romain et le Mont Palatin', 'description' => 'Adjacent au Colisée s\'étend le Forum Romain, cœur battant du monde antique pendant plus de mille ans. Le Temple de Saturne (497 av. J.-C.) conserve huit de ses colonnes de granit gris. L\'Arc de Titus (81 apr. J.-C.), érigé pour commémorer le sac de Jérusalem, présente des reliefs montrant des soldats romains portant le Candélabre du Temple. Le Temple de Vesta, où les Vestales entretenaient la flamme sacrée de Rome, est l\'une des ruines les plus évocatrices. Montez au Mont Palatin — selon la légende, le lieu de fondation de Rome par Romulus en 753 av. J.-C. — pour des vues panoramiques spectaculaires.'],
        'de' => ['title' => 'Forum Romanum & Palatin-Hügel', 'description' => 'Unmittelbar neben dem Kolosseum liegt das Forum Romanum, das pulsierende Herz der antiken römischen Welt über tausend Jahre lang. Der Saturntempel (497 v. Chr.) steht noch mit acht seiner grauen Granitsäulen. Der Titusbogen (81 n. Chr.), errichtet zur Erinnerung an die Plünderung Jerusalems, zeigt Reliefs mit römischen Soldaten, die die Menora aus dem Tempel tragen. Der Vesta-Tempel, wo die Vestalinnen die heilige Flamme Roms am Brennen hielten, ist eine der eindrucksvollsten Ruinen. Besteigen Sie den Palatin — laut Legende der Gründungsort Roms durch Romulus 753 v. Chr. — für spektakuläre Panoramablicke.'],
        'it' => ['title' => 'Foro Romano e Colle Palatino', 'description' => 'Adiacente al Colosseo si estende il Foro Romano, cuore pulsante del mondo antico per oltre mille anni. Il Tempio di Saturno (497 a.C.) conserva otto delle sue colonne di granito grigio. L\'Arco di Tito (81 d.C.), eretto per commemorare il sacco di Gerusalemme, presenta rilievi con soldati romani che portano la Menorah dal Tempio. Il Tempio di Vesta, dove le Vestali mantenevano accesa la fiamma sacra di Roma, è una delle rovine più evocative. Salite al Colle Palatino — secondo la leggenda, il luogo della fondazione di Roma da parte di Romolo nel 753 a.C. — per viste panoramiche spettacolari.'],
        'el' => ['title' => 'Ρωμαϊκό Φόρουμ και Παλατινός Λόφος', 'description' => 'Ακριβώς δίπλα στο Κολοσσαίο βρίσκεται το Ρωμαϊκό Φόρουμ — η ζωογόνος καρδιά του αρχαίου ρωμαϊκού κόσμου για πάνω από χίλια χρόνια. Ο Ναός του Κρόνου (497 π.Χ.) στέκει ακόμα με οκτώ από τις γκρίζες γρανιτένιες κολόνες του. Η Αψίδα του Τίτου (81 μ.Χ.), που ανεγέρθηκε για να τιμήσει την κατάκτηση της Ιερουσαλήμ, φέρει ανάγλυφα που δείχνουν Ρωμαίους στρατιώτες να κουβαλούν τη Μενόρα. Ο Ναός της Εστίας, όπου οι Εστιάδες διατηρούσαν αναμμένη τη φλόγα της Ρώμης, είναι ένα από τα πιο εντυπωσιακά ερείπια. Ανεβείτε στον Παλατινό Λόφο — σύμφωνα με την παράδοση, τον τόπο ίδρυσης της Ρώμης από τον Ρωμύλο το 753 π.Χ. — για εντυπωσιακές πανοραμικές θέες.'],
      ],
    ],
    [
      'title' => 'Pantheon — Temple of the Gods',
      'order' => 3,
      'location' => ['lat' => 41.8986, 'lng' => 12.4769],
      'description' => 'A twenty-minute walk northwest from the Forum brings you to one of the best-preserved buildings from antiquity and arguably the most influential building in Western architectural history: the Pantheon. Built as a temple to all the gods of ancient Rome, the current structure was commissioned by Emperor Hadrian around 125 AD to replace an earlier temple built by Marcus Agrippa — whose name, confusingly, still appears on the inscription above the entrance porch. The Pantheon\'s survival over nearly 2,000 years is largely due to its conversion into a Christian church in 609 AD, which saved it from the quarrying that destroyed so many other Roman monuments. The building\'s engineering genius is concentrated in its extraordinary dome: at 43.3 metres in diameter, it remained the world\'s largest dome for over 1,300 years until Brunelleschi completed the Florence Cathedral dome in 1436. The dome is a perfect hemisphere — if extended downward, it would exactly touch the floor — and at its apex is the oculus, an open circular hole 8.8 metres in diameter that is the building\'s only source of natural light. The oculus is open to the sky: on rainy days, a slight slope in the floor and concealed drainage channels remove the water that falls in. The tombs of Renaissance painter Raphael and King Victor Emmanuel II of unified Italy are among several notable burials within. Entrance is now ticketed following years of free admission.',
      'translations' => [
        'es' => ['title' => 'El Panteón — templo de los dioses', 'description' => 'A veinte minutos a pie del Foro se encuentra el Panteón, uno de los edificios antiguos mejor conservados del mundo y posiblemente el más influyente de la historia de la arquitectura occidental. Construido por el Emperador Adriano alrededor del año 125 d.C., su cúpula de 43,3 metros de diámetro fue la más grande del mundo durante más de 1.300 años. La cúpula es un hemisferio perfecto; en su cúspide se abre el óculo, un agujero circular de 8,8 metros de diámetro que es la única fuente de luz natural. El óculo está abierto al cielo: los días de lluvia, una ligera pendiente en el suelo y canales de drenaje ocultos evacuaban el agua. Alberga las tumbas de Rafael y del Rey Víctor Manuel II.'],
        'fr' => ['title' => 'Le Panthéon — temple des dieux', 'description' => 'À vingt minutes à pied du Forum se trouve le Panthéon, l\'un des bâtiments antiques les mieux conservés et sans doute le plus influent de l\'histoire de l\'architecture occidentale. Construit par l\'Empereur Hadrien vers 125 apr. J.-C., son dôme de 43,3 mètres de diamètre est resté le plus grand au monde pendant plus de 1 300 ans. Le dôme est un hémisphère parfait ; à son sommet s\'ouvre l\'oculus, un trou circulaire de 8,8 mètres de diamètre, seule source de lumière naturelle. L\'oculus est ouvert au ciel : les jours de pluie, une légère pente du sol évacue l\'eau. Il abrite les tombeaux de Raphaël et du Roi Victor-Emmanuel II.'],
        'de' => ['title' => 'Das Pantheon — Tempel der Götter', 'description' => 'Zwanzig Gehminuten nordwestlich vom Forum erreichen Sie das Pantheon, eines der besterhaltenen antiken Gebäude und wohl das einflussreichste in der Geschichte der westlichen Architektur. Um 125 n. Chr. von Kaiser Hadrian erbaut, blieb seine Kuppel mit 43,3 Metern Durchmesser über 1.300 Jahre die größte der Welt. Die Kuppel ist eine perfekte Halbkugel; an ihrem Scheitel öffnet sich der Okulus, ein kreisrundes Loch von 8,8 Metern Durchmesser als einzige natürliche Lichtquelle. Bei Regen leiten eine leichte Bodenneigung und verborgene Kanäle das Wasser ab. Hier befinden sich die Gräber von Raffael und König Viktor Emanuel II.'],
        'it' => ['title' => 'Il Pantheon — tempio degli dèi', 'description' => 'A venti minuti a piedi dal Foro si trova il Pantheon, uno degli edifici antichi meglio conservati e probabilmente il più influente nella storia dell\'architettura occidentale. Costruito dall\'Imperatore Adriano intorno al 125 d.C., la sua cupola di 43,3 metri di diametro rimase la più grande al mondo per oltre 1.300 anni. La cupola è un emisfero perfetto; al suo apice si apre l\'oculo, un foro circolare di 8,8 metri di diametro, unica fonte di luce naturale. L\'oculo è aperto al cielo: nei giorni di pioggia, una leggera pendenza del pavimento e canali nascosti evacuano l\'acqua. Ospita le tombe di Raffaello e del Re Vittorio Emanuele II.'],
        'el' => ['title' => 'Πάνθεον — ναός των θεών', 'description' => 'Είκοσι λεπτά με τα πόδια βορειοδυτικά από το Φόρουμ φέρνουν στο Πάνθεον, ένα από τα καλύτερα διατηρημένα αρχαία κτίρια και αναμφίβολα το πιο επιδραστικό κτίριο στη δυτική αρχιτεκτονική ιστορία. Χτισμένο από τον Αυτοκράτορα Αδριανό γύρω στο 125 μ.Χ., βρίσκεται σε ευρεία χρήση για σχεδόν 2.000 χρόνια. Ο τρούλος με διάμετρο 43,3 μέτρων παρέμεινε ο μεγαλύτερος στον κόσμο για πάνω από 1.300 χρόνια. Ο τρούλος είναι ένα τέλειο ημισφαίριο· στην κορυφή του ανοίγεται το οπαίο, ένα κυκλικό άνοιγμα 8,8 μέτρων διαμέτρου, η μοναδική φυσική πηγή φωτός. Εδώ βρίσκονται οι τάφοι του Ραφαήλ και του Βασιλιά Βίκτωρα Εμμανουήλ Β΄.'],
      ],
    ],
    [
      'title' => 'Trevi Fountain — The Most Famous Fountain in the World',
      'order' => 4,
      'location' => ['lat' => 41.9009, 'lng' => 12.4833],
      'description' => 'Complete your Roman journey at the Trevi Fountain — the Fontana di Trevi — the largest Baroque fountain in Rome and the most famous fountain in the world. Built into the back wall of Palazzo Poli, the fountain was designed by Nicola Salvi and completed in 1762, nearly three centuries after Pope Nicholas V first commissioned a new terminal fountain for the ancient Acqua Vergine aqueduct in 1453. The central figure is Neptune, god of the sea, riding a shell-shaped chariot pulled by two sea horses — one calm, one wild — guided by Tritons, representing the sea in different moods. The theatrical composition, with figures carved from Carrara marble against a triumphal arch backdrop, is a masterpiece of the late Baroque style. The tradition of throwing a coin into the fountain — which guarantees a return to Rome — was popularised by the 1954 film Three Coins in the Fountain and immortalised by Federico Fellini\'s La Dolce Vita in 1960, in which Anita Ekberg wades through the fountain in an iconic scene. Today approximately €3,000 worth of coins are thrown into the fountain every day — all collected nightly by the city authorities and donated to a charity that provides food for Rome\'s poor. Arrive very early in the morning (before 7am) to experience the fountain without crowds and to see the beautiful play of light on the water and marble in the golden morning sunshine.',
      'translations' => [
        'es' => ['title' => 'Fontana di Trevi — la fuente más famosa del mundo', 'description' => 'Complete su recorrido romano en la Fontana di Trevi, la mayor fuente barroca de Roma y la más famosa del mundo. Diseñada por Nicola Salvi y completada en 1762, la figura central es Neptuno sobre un carro en forma de concha tirado por dos caballos marinos — uno tranquilo, uno salvaje — guiados por tritones. La tradición de lanzar una moneda a la fuente — que garantiza el regreso a Roma — fue popularizada por la película Tres Monedas en la Fuente (1954) e inmortalizada por Fellini en La Dolce Vita (1960). Cada día se lanzan monedas por valor de unos 3.000€, recogidas nocturnamente y donadas a una organización benéfica. Llegue antes de las 7h para disfrutarla sin aglomeraciones.'],
        'fr' => ['title' => 'La Fontaine de Trevi — la plus célèbre fontaine du monde', 'description' => 'Terminez votre parcours romain à la Fontaine de Trevi, la plus grande fontaine baroque de Rome et la plus célèbre au monde. Conçue par Nicola Salvi et achevée en 1762, la figure centrale est Neptune sur un char en forme de coquille tiré par deux chevaux marins — l\'un calme, l\'autre sauvage — guidés par des Tritons. La tradition de lancer une pièce dans la fontaine — qui garantit un retour à Rome — a été popularisée par le film Trois pièces dans la fontaine (1954) et immortalisée par Fellini dans La Dolce Vita (1960). Chaque jour, environ 3 000€ de pièces sont lancées, collectées chaque nuit et données à une association caritative. Arrivez avant 7h pour en profiter sans foule.'],
        'de' => ['title' => 'Trevi-Brunnen — der berühmteste Brunnen der Welt', 'description' => 'Beenden Sie Ihre römische Reise am Trevi-Brunnen — dem größten Barockbrunnen Roms und dem berühmtesten Brunnen der Welt. Von Nicola Salvi entworfen und 1762 vollendet, zeigt die zentrale Figur Neptun auf einem muschelförmigen Wagen, gezogen von zwei Seepferden — einem ruhigen, einem wilden — geführt von Tritonen. Die Tradition, eine Münze in den Brunnen zu werfen — die eine Rückkehr nach Rom garantiert — wurde durch den Film Drei Münzen im Brunnen (1954) populär und durch Fellinis La Dolce Vita (1960) verewigt. Täglich werden Münzen im Wert von etwa 3.000€ hineingeworfen, nachts gesammelt und an eine Wohltätigkeitsorganisation gespendet. Kommen Sie vor 7 Uhr für ein Erlebnis ohne Menschenmassen.'],
        'it' => ['title' => 'Fontana di Trevi — la fontana più famosa del mondo', 'description' => 'Concludete il vostro viaggio romano alla Fontana di Trevi, la più grande fontana barocca di Roma e la più famosa al mondo. Progettata da Nicola Salvi e completata nel 1762, la figura centrale è Nettuno su un cocchio a forma di conchiglia trainato da due cavalli marini — uno calmo, uno selvaggio — guidati da tritoni. La tradizione di gettare una moneta nella fontana — che garantisce il ritorno a Roma — fu resa popolare dal film Tre soldi nella fontana (1954) e immortalata da Fellini ne La Dolce Vita (1960). Ogni giorno vengono gettate monete per circa 3.000€, raccolte ogni notte e donate in beneficenza. Arrivate prima delle 7 per godervi la fontana senza folla.'],
        'el' => ['title' => 'Φοντάνα ντι Τρέβι — το πιο διάσημο συντριβάνι στον κόσμο', 'description' => 'Ολοκληρώστε το ρωμαϊκό ταξίδι σας στη Φοντάνα ντι Τρέβι, το μεγαλύτερο μπαρόκ συντριβάνι της Ρώμης και το πιο διάσημο συντριβάνι στον κόσμο. Σχεδιασμένο από τον Nicola Salvi και ολοκληρωμένο το 1762, η κεντρική μορφή είναι ο Ποσειδώνας πάνω σε ένα κοχυλιόσχημο άρμα που σύρεται από δύο άλογα — ένα ήρεμο, ένα άγριο — οδηγούμενο από Τρίτωνες. Η παράδοση να ρίχνεις ένα νόμισμα στο συντριβάνι — που εγγυάται την επιστροφή στη Ρώμη — έγινε δημοφιλής με την ταινία Τρία νομίσματα στο Συντριβάνι (1954) και αθανατίστηκε από τον Φελίνι στη Ντόλτσε Βίτα (1960). Καθημερινά ρίχνονται νομίσματα αξίας περίπου 3.000€, που συλλέγονται νυκτερινά και δωρίζονται σε φιλανθρωπικούς σκοπούς. Φτάστε πριν τις 7 π.μ. για να την απολαύσετε χωρίς πλήθη.'],
      ],
    ],
    [
      'title' => 'Vatican Museums & Sistine Chapel',
      'order' => 5,
      'location' => ['lat' => 41.9065, 'lng' => 12.4536],
      'description' => 'Cross the Tiber River to Vatican City — the world\'s smallest sovereign state at just 44 hectares — to visit the Vatican Museums, one of the largest and most important museum complexes in the world. Founded by Pope Julius II in the early 16th century, the museums contain the accumulated artistic treasures of the Catholic Church spanning nearly 2,000 years of history, displayed across 54 galleries and covering 7 kilometres of corridors if walked in their entirety. The journey through the museums is itself a remarkable experience: the Gallery of Maps features 40 topographical maps of Italy painted between 1580 and 1585 with extraordinary precision; the Gallery of Tapestries displays Flemish tapestries woven from Raphael\'s cartoons in the 1520s; and the Hall of the Candelabra is lined with ancient Roman sculpture of the highest quality. The inevitable and absolute highlight, however, is the Sistine Chapel. Painted by Michelangelo between 1508 and 1512 (the ceiling) and 1536 and 1541 (the Last Judgement on the altar wall), this is one of the supreme achievements in the history of Western art. The famous central panel depicting the Creation of Adam — in which God\'s finger almost touches the languid hand of the first man — is the most reproduced detail, but the ceiling as a whole is a staggering feat of physical endurance and artistic genius by a sculptor who had never previously worked in fresco on any significant scale. Photography without flash is permitted in the museums but not in the Sistine Chapel. Book tickets months in advance for July and August.',
      'translations' => [
        'es' => ['title' => 'Museos Vaticanos y Capilla Sixtina', 'description' => 'Cruce el Tíber hasta la Ciudad del Vaticano — el estado soberano más pequeño del mundo con sólo 44 hectáreas — para visitar los Museos Vaticanos, uno de los mayores complejos museísticos del mundo con 54 galerías y 7 kilómetros de pasillos. La Galería de los Mapas presenta 40 mapas topográficos de Italia pintados entre 1580 y 1585. El punto culminante indiscutible es la Capilla Sixtina, pintada por Miguel Ángel entre 1508 y 1512 (el techo) y 1536-1541 (el Juicio Final). El famoso panel central de la Creación de Adán es el detalle más reproducido, pero el techo en su conjunto es una hazaña sobrecogedora de genio artístico. Reserve entradas con meses de antelación en julio y agosto.'],
        'fr' => ['title' => 'Les Musées du Vatican et la Chapelle Sixtine', 'description' => 'Traversez le Tibre vers la Cité du Vatican — le plus petit État souverain du monde avec seulement 44 hectares — pour visiter les Musées du Vatican, l\'un des plus importants complexes muséaux au monde avec 54 galeries et 7 kilomètres de couloirs. La Galerie des Cartes présente 40 cartes topographiques de l\'Italie peintes entre 1580 et 1585. Le point culminant absolu est la Chapelle Sixtine, peinte par Michel-Ange entre 1508 et 1512 (le plafond) et 1536-1541 (le Jugement Dernier). Le célèbre panneau central de la Création d\'Adam est le détail le plus reproduit. Réservez des mois à l\'avance pour juillet et août.'],
        'de' => ['title' => 'Vatikanische Museen & Sixtinische Kapelle', 'description' => 'Überqueren Sie den Tiber zur Vatikanstadt — dem kleinsten souveränen Staat der Welt mit nur 44 Hektar — um die Vatikanischen Museen zu besuchen, einen der wichtigsten Museumskomplexe der Welt mit 54 Galerien und 7 Kilometer Korridoren. Die Galerie der Landkarten zeigt 40 topographische Karten Italiens, gemalt zwischen 1580 und 1585. Der absolute Höhepunkt ist die Sixtinische Kapelle, zwischen 1508 und 1512 (Decke) und 1536-1541 (Jüngstes Gericht) von Michelangelo gemalt. Das berühmte zentrale Bild der Erschaffung Adams ist das meistreproduzierte Detail. Buchen Sie Monate im Voraus für Juli und August.'],
        'it' => ['title' => 'Musei Vaticani e Cappella Sistina', 'description' => 'Attraversate il Tevere verso la Città del Vaticano — il più piccolo stato sovrano del mondo con soli 44 ettari — per visitare i Musei Vaticani, uno dei più importanti complessi museali del mondo con 54 gallerie e 7 chilometri di corridoi. La Galleria delle Carte Geografiche presenta 40 mappe topografiche dell\'Italia dipinte tra il 1580 e il 1585. Il culmine assoluto è la Cappella Sistina, dipinta da Michelangelo tra il 1508 e il 1512 (il soffitto) e il 1536-1541 (il Giudizio Universale). Il celebre pannello centrale della Creazione di Adamo è il dettaglio più riprodotto. Prenotate con mesi di anticipo per luglio e agosto.'],
        'el' => ['title' => 'Μουσεία Βατικανού και Καπέλα Σιστίνα', 'description' => 'Διασχίστε τον ποταμό Τίβερη προς το Βατικανό — το μικρότερο κυρίαρχο κράτος στον κόσμο με μόλις 44 εκτάρια — για να επισκεφθείτε τα Μουσεία Βατικανού, ένα από τα μεγαλύτερα μουσειακά συγκροτήματα στον κόσμο με 54 γκαλερί και 7 χιλιόμετρα διαδρόμων. Η αναπόφευκτη και απόλυτη κορύφωση είναι η Καπέλα Σιστίνα. Ζωγραφισμένη από τον Μιχαήλ Άγγελο μεταξύ 1508 και 1512 (η οροφή) και 1536-1541 (η Τελευταία Κρίση), αυτό είναι ένα από τα ύψιστα επιτεύγματα στην ιστορία της δυτικής τέχνης. Το διάσημο κεντρικό πάνελ που απεικονίζει τη Δημιουργία του Αδάμ είναι η πιο αναπαραγόμενη λεπτομέρεια. Κλείστε εισιτήρια μήνες νωρίτερα για Ιούλιο και Αύγουστο.'],
      ],
    ],
  ],
];

// ============================================================
// TOUR — BUDAPEST: Imperial Baths, Ruin Bars & the Danube
// ============================================================
$tours[] = [
  'title' => 'Imperial Budapest: Baths, Ruin Bars & the Danube Bend',
  'description' => 'Budapest is one of Europe\'s most dramatically beautiful capital cities, a place where a 19th-century imperial metropolis sits astride a river of mythic importance, where Ottoman thermal baths bubble beneath neo-Gothic parliament buildings, and where the raw creativity of post-communist counterculture has transformed derelict Jewish Quarter tenements into some of the most inventive bars and cultural spaces on the continent. The city is technically two cities, Buda on the hilly western bank and Pest on the flat eastern bank, unified in 1873 into a single capital whose ambition was to rival Vienna as the co-capital of the Austro-Hungarian Empire. The result is a city of magnificent contradictions: Habsburg grandeur and Stalinist brutalism, medieval castle ramparts and modernist ruin bars, the ancient thermal waters of Roman Aquincum and the contemporary energy of a city that has rediscovered its confidence after decades of communist suppression. The entire Danube bank, on both sides, is a UNESCO World Heritage Site, and the view from the Fisherman\'s Bastion across the river to the illuminated Parliament at night is one of the great urban spectacles on earth.',
  'duration' => 210,
  'country' => 'Hungary',
  'city' => 'Budapest',
  'location' => ['lat' => 47.4979, 'lng' => 19.0402],
  'translations' => [
    'es' => [
      'title' => 'Budapest imperial: baños termales, bares en ruinas y el Danubio',
      'description' => 'Budapest es una de las capitales europeas más hermosas y dramáticas, un lugar donde una metrópoli imperial del siglo XIX se alza a orillas de un río de importancia mítica, donde los baños termales otomanos brotan bajo edificios neogóticos del Parlamento y donde la creatividad de la contracultura poscomunista ha convertido antiguos edificios del barrio judío en algunos de los bares y espacios culturales más ingeniosos del continente. La ciudad son en realidad dos ciudades, Buda, en la orilla occidental y montañosa, y Pest, en la orilla oriental y llana, unificadas en 1873 en una sola capital cuya ambición era rivalizar con Viena como co-capital del Imperio austrohúngaro. El resultado es una ciudad de magníficos contrastes: la grandeza de los Habsburgo y el brutalismo estalinista, las murallas medievales del castillo y los bares de ruinas modernistas, las antiguas aguas termales de la Aquincum romana y la energía contemporánea de una ciudad que ha recuperado su confianza tras décadas de represión comunista. Toda la ribera del Danubio, en ambas orillas, es Patrimonio de la Humanidad de la UNESCO, y la vista desde el Bastión de los Pescadores hacia el Parlamento iluminado por la noche es uno de los grandes espectáculos urbanos del mundo.',
    ],
    'fr' => [
      'title' => 'Budapest impérial : thermes, bars en ruines et le Danube',
      'description' => 'Budapest est l’une des capitales européennes les plus belles et les plus spectaculaires, un lieu où une métropole impériale du XIXe siècle s’élève au bord d’un fleuve d’importance mythique, où des thermes ottomans bouillonnent sous des bâtiments néogothiques du Parlement, et où la créativité brute de la contre-culture postcommuniste a transformé des immeubles délabrés du quartier juif en certains des bars et espaces culturels les plus inventifs du continent. La ville est en réalité composée de deux villes, Buda sur la rive occidentale vallonnée et Pest sur la rive orientale, unifiées en 1873 en une capitale unique dont l’ambition était de rivaliser avec Vienne comme co-capitale de l’Empire austro-hongrois. Il en résulte une ville de magnifiques contrastes : grandeur des Habsbourg et brutalité stalinienne, remparts médiévaux du château et bars en ruine modernistes, eaux thermales antiques d’Aquincum romaine et énergie contemporaine d’une ville qui a retrouvé sa confiance après des décennies de répression communiste. L’ensemble des rives du Danube, des deux côtés, est inscrit au patrimoine mondial de l’UNESCO, et la vue depuis le Bastion des Pêcheurs sur le Parlement illuminé la nuit compte parmi les grands spectacles urbains de la planète.',
    ],
    'de' => [
      'title' => 'Kaiserliches Budapest: Thermalbäder, Ruinenbars und die Donau',
      'description' => 'Budapest ist eine der dramatisch schönsten Hauptstädte Europas, ein Ort, an dem sich eine imperiale Metropole des 19. Jahrhunderts an einen Fluss von mythischer Bedeutung schmiegt, wo unter neogotischen Parlamentsgebäuden osmanische Thermalbäder sprudeln und die rohe Kreativität der postkommunistischen Gegenkultur verfallene Häuser des jüdischen Viertels in einige der einfallsreichsten Bars und Kulturorte des Kontinents verwandelt hat. Die Stadt besteht technisch aus zwei Städten, Buda am hügeligen Westufer und Pest am flachen Ostufer, die 1873 zu einer einzigen Hauptstadt vereint wurden, deren Ziel es war, Wien als Mit-Hauptstadt der österreichisch-ungarischen Monarchie herauszufordern. Das Ergebnis ist eine Stadt großartiger Gegensätze: habsburgische Pracht und stalinistischer Brutalismus, mittelalterliche Burgmauern und moderne Ruinenbars, die antiken Thermalquellen des römischen Aquincum und die heutige Energie einer Stadt, die nach Jahrzehnten kommunistischer Unterdrückung ihr Selbstvertrauen wiedergefunden hat. Das gesamte Donauufer auf beiden Seiten ist UNESCO-Welterbe, und der Blick vom Fischerbastei über den Fluss auf das beleuchtete Parlament bei Nacht gehört zu den großen urbanen Sehenswürdigkeiten der Welt.',
    ],
    'it' => [
      'title' => 'Budapest imperiale: terme, bar in rovina e il Danubio',
      'description' => 'Budapest è una delle capitali europee più belle e spettacolari, un luogo in cui una metropoli imperiale del XIX secolo si affaccia su un fiume di importanza mitica, dove le terme ottomane ribollono sotto edifici neogotici del Parlamento e la creatività della controcultura postcomunista ha trasformato i palazzi fatiscenti del quartiere ebraico in alcuni dei bar e spazi culturali più inventivi del continente. La città è in realtà composta da due città, Buda sulla sponda occidentale collinare e Pest su quella orientale e pianeggiante, unificate nel 1873 in un’unica capitale la cui ambizione era competere con Vienna come co-capitale dell’Impero austro-ungarico. Il risultato è una città di magnifiche contraddizioni: lo splendore asburgico e il brutalismo stalinista, le mura medievali del castello e i ruin bar modernisti, le antiche acque termali della romana Aquincum e l’energia contemporanea di una città che ha ritrovato la propria fiducia dopo decenni di repressione comunista. Tutto il lungofiume del Danubio, su entrambe le rive, è Patrimonio dell’Umanità UNESCO, e la vista dal Bastione dei Pescatori sul Parlamento illuminato di notte è uno dei grandi spettacoli urbani del mondo.',
    ],
    'el' => [
      'title' => 'Αυτοκρατορική Βουδαπέστη: θερμά λουτρά, ruin bars και ο Δούναβης',
      'description' => 'Η Βουδαπέστη είναι μία από τις πιο εντυπωσιακά όμορφες πρωτεύουσες της Ευρώπης, ένας τόπος όπου μια αυτοκρατορική μητρόπολη του 19ου αιώνα απλώνεται δίπλα σε ένα ποτάμι μυθικής σημασίας, όπου οθωμανικά θερμά λουτρά αναβλύζουν κάτω από νεογοτθικά κτίρια του Κοινοβουλίου και η ακατέργαστη δημιουργικότητα της μετακομμουνιστικής αντικουλτούρας έχει μεταμορφώσει ερειπωμένα κτίρια της εβραϊκής συνοικίας σε μερικά από τα πιο ευρηματικά μπαρ και πολιτιστικά στέκια της Ευρώπης. Η πόλη είναι ουσιαστικά δύο πόλεις, η Βούδα στη λοφώδη δυτική όχθη και η Πέστη στην επίπεδη ανατολική, ενωμένες το 1873 σε μία πρωτεύουσα που φιλοδοξούσε να ανταγωνιστεί τη Βιέννη ως συν-πρωτεύουσα της Αυστροουγγρικής Αυτοκρατορίας. Το αποτέλεσμα είναι μια πόλη με σπουδαίες αντιθέσεις: χαψβουργική μεγαλοπρέπεια και σταλινικός μπρουταλισμός, μεσαιωνικά τείχη κάστρου και μοντερνιστικά ruin bars, τα αρχαία θερμά νερά της ρωμαϊκής Ακουίνκουμ και τη σύγχρονη ενέργεια μιας πόλης που ξαναβρήκε την αυτοπεποίθησή της μετά από δεκαετίες κομμουνιστικής καταπίεσης. Ολόκληρη η όχθη του Δούναβη και στις δύο πλευρές αποτελεί Μνημείο Παγκόσμιας Κληρονομιάς της UNESCO, και η θέα από το Προμαχώνα των Ψαράδων προς το φωταγωγημένο Κοινοβούλιο τη νύχτα είναι ένα από τα σπουδαιότερα αστικά θεάματα στον κόσμο.',
    ],
  ],
  'steps' => [
    [
      'title' => 'Buda Castle & the Castle District',
      'order' => 1,
      'location' => ['lat' => 47.4960, 'lng' => 19.0399],
      'description' => 'Begin on the Buda side of the river at the Castle District, the Várnegyed, a UNESCO-listed plateau of medieval streets, baroque palaces, Gothic churches, and royal history perched 60 metres above the Danube on Castle Hill. The fortified settlement here dates to the 13th century, when King Béla IV ordered a royal castle built after the Mongol invasion of 1241 laid waste to the undefended lowland city, a catastrophe that killed half the population of medieval Hungary and fundamentally reshaped how Hungarians built and defended their cities. The Royal Palace that dominates the southern end of the hill today is largely an 18th and 19th-century reconstruction: the original medieval palace was destroyed during the Ottoman siege of 1686, rebuilt under Habsburg rule, badly damaged in the Second World War, and reconstructed again under communist rule in a more austere neo-Baroque style. Today it houses the Hungarian National Gallery and the Budapest History Museum, both worth visiting. The true character of the Castle District is found not in the palace but in the medieval street plan between the Fisherman\'s Bastion and Matthias Church: Holy Trinity Square, Uri utca, Táncsics utca, and the network of Gothic sedilia, stone window seats carved into doorways for the use of the urban poor waiting to petition their noble hosts, that survive from the 14th and 15th centuries. Matthias Church, originally built in 1015 and reconstructed in Gothic style in the 14th century, is one of the most beautiful churches in Hungary, its diamond-patterned polychrome tile roof visible from across the river.',
      'translations' => [
        'es' => [
          'title' => 'Castillo de Buda y distrito del castillo',
          'description' => 'Comience en la orilla de Buda, en el distrito del castillo, el Várnegyed, una meseta declarada Patrimonio de la Humanidad con calles medievales, palacios barrocos, iglesias góticas e historia real situada a 60 metros sobre el Danubio, en la colina del castillo. El asentamiento fortificado data del siglo XIII, cuando el rey Béla IV ordenó construir un castillo real tras la invasión mongola de 1241, que arrasó la ciudad llana y dejó una huella profunda en la forma en que los húngaros levantaron y defendieron sus ciudades. El Palacio Real que domina hoy el extremo sur de la colina es en gran parte una reconstrucción de los siglos XVIII y XIX. Hoy alberga la Galería Nacional Húngara y el Museo de Historia de Budapest. El verdadero carácter del barrio se encuentra en el trazado medieval entre el Bastión de los Pescadores y la Iglesia de Matías: la plaza de la Santísima Trinidad, la calle Uri, la calle Táncsics y los antiguos asientos góticos de piedra junto a las puertas. La Iglesia de Matías, reconstruida en estilo gótico en el siglo XIV, es una de las más bellas de Hungría y destaca por su tejado de azulejos policromados.',
        ],
        'fr' => [
          'title' => 'Le château de Buda et le quartier du château',
          'description' => 'Commencez sur la rive de Buda, dans le quartier du château, le Várnegyed, un plateau inscrit au patrimoine mondial avec ses rues médiévales, ses palais baroques, ses églises gothiques et son histoire royale, perché à 60 mètres au-dessus du Danube sur la colline du château. Le noyau fortifié remonte au XIIIe siècle, lorsque le roi Béla IV ordonna la construction d’un château royal après l’invasion mongole de 1241, qui ravagea la ville basse sans défense et marqua profondément la manière dont les Hongrois construisirent et défendirent leurs villes. Le palais royal qui domine aujourd’hui l’extrémité sud de la colline est en grande partie une reconstruction des XVIIIe et XIXe siècles. Il abrite aujourd’hui la Galerie nationale hongroise et le musée d’histoire de Budapest. Le véritable caractère du quartier se découvre dans le plan médiéval situé entre le Bastion des Pêcheurs et l’église Matthias : la place de la Sainte-Trinité, la rue Uri, la rue Táncsics et les anciens sièges de pierre gothiques près des portes. L’église Matthias, reconstruite dans le style gothique au XIVe siècle, est l’une des plus belles de Hongrie et se distingue par son toit de tuiles polychromes.',
        ],
        'de' => [
          'title' => 'Burg Buda und das Burgviertel',
          'description' => 'Beginnen Sie auf der Buda-Seite des Flusses im Burgviertel, dem Várnegyed, einer UNESCO-geschützten Hochebene mit mittelalterlichen Straßen, Barockpalästen, gotischen Kirchen und königlicher Geschichte, die 60 Meter über der Donau auf dem Burgberg liegt. Die befestigte Siedlung reicht ins 13. Jahrhundert zurück, als König Béla IV. nach der mongolischen Invasion von 1241 den Bau einer königlichen Burg anordnete, nachdem die ungeschützte Tieflandstadt verwüstet worden war. Der heutige Königspalast am Südende des Hügels ist größtenteils eine Rekonstruktion des 18. und 19. Jahrhunderts. Heute beherbergt er die Ungarische Nationalgalerie und das Budapester Historische Museum. Den eigentlichen Charakter des Viertels findet man im mittelalterlichen Straßennetz zwischen Fischerbastei und Matthiaskirche: dem Heiligen-Treue-Platz, der Uri utca, der Táncsics utca und den gotischen steinernen Fenstersitzen an den Türen. Die Matthiaskirche, ursprünglich 1015 erbaut und im 14. Jahrhundert gotisch umgestaltet, zählt zu den schönsten Kirchen Ungarns und ist für ihr rautenförmiges, buntes Ziegeldach bekannt.',
        ],
        'it' => [
          'title' => 'Castello di Buda e quartiere del castello',
          'description' => 'Iniziate sul lato di Buda del fiume, nel quartiere del castello, il Várnegyed, un altopiano dichiarato Patrimonio dell’Umanità con strade medievali, palazzi barocchi, chiese gotiche e storia reale, sospeso a 60 metri sopra il Danubio sulla collina del castello. L’insediamento fortificato risale al XIII secolo, quando re Béla IV ordinò la costruzione di un castello reale dopo che l’invasione mongola del 1241 aveva devastato la città bassa non difesa. Il Palazzo Reale che domina oggi l’estremità meridionale della collina è in gran parte una ricostruzione dei secoli XVIII e XIX. Oggi ospita la Galleria Nazionale Ungherese e il Museo di Storia di Budapest. Il vero carattere del quartiere si trova però nel tracciato medievale tra il Bastione dei Pescatori e la Chiesa di Mattia: Piazza della Santissima Trinità, via Uri, via Táncsics e la rete di sedilia gotici, sedili di pietra incavati accanto alle porte per chi attendeva di presentare una petizione ai nobili. La Chiesa di Mattia, ricostruita in stile gotico nel XIV secolo, è una delle chiese più belle dell’Ungheria e si distingue per il tetto di tegole policrome a motivo ромboidale.',
        ],
        'el' => [
          'title' => 'Το Κάστρο της Βούδας και η Καστροπολιτεία',
          'description' => 'Ξεκινήστε από την πλευρά της Βούδας, στην Καστροπολιτεία, το Várnegyed, ένα μνημειακό οροπέδιο μεσαιωνικών δρόμων, μπαρόκ παλατιών, γοτθικών εκκλησιών και βασιλικής ιστορίας, που υψώνεται 60 μέτρα πάνω από τον Δούναβη στον λόφο του Κάστρου. Ο οχυρωμένος οικισμός χρονολογείται από τον 13ο αιώνα, όταν ο βασιλιάς Béla IV διέταξε την ανέγερση βασιλικού κάστρου μετά την καταστροφή της πεδινής πόλης από τη μογγολική εισβολή του 1241, ένα γεγονός που σκότωσε τη μισή πληθυσμό της μεσαιωνικής Ουγγαρίας και άλλαξε ριζικά τον τρόπο με τον οποίο οι Ούγγροι έκτιζαν και υπερασπίζονταν τις πόλεις τους. Το Βασιλικό Παλάτι που δεσπόζει σήμερα στο νότιο άκρο του λόφου είναι σε μεγάλο βαθμό ανακατασκευή του 18ου και 19ου αιώνα. Σήμερα στεγάζει την Ουγγρική Εθνική Πινακοθήκη και το Μουσείο Ιστορίας της Βουδαπέστης. Ο πραγματικός χαρακτήρας της περιοχής βρίσκεται στο μεσαιωνικό οδικό πλέγμα ανάμεσα στο Προμαχώνα των Ψαράδων και την Εκκλησία του Ματθία: την Πλατεία της Αγίας Τριάδας, την οδό Uri, την οδό Táncsics και το δίκτυο γοτθικών sedilia, λίθινων καθισμάτων στις εισόδους για τους φτωχούς κατοίκους που περίμεναν να ζητήσουν βοήθεια από τους ευγενείς. Η Εκκλησία του Ματθία, αρχικά χτισμένη το 1015 και ανακατασκευασμένη σε γοτθικό ύφος τον 14ο αιώνα, είναι μία από τις πιο όμορφες εκκλησίες της Ουγγαρίας, με τη ρομβοειδή πολύχρωμη κεραμοσκεπή της να φαίνεται από την απέναντι όχθη.',
        ],
      ],
